import React, { useState, useEffect } from 'react';
import { Container, Form, Button, Card, Row, Col, Badge, Spinner } from 'react-bootstrap';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faSearch, faFilter, faClock, faCode, faBuilding, faTags, faBookmark, faStar } from '@fortawesome/free-solid-svg-icons';
import '../styles/AdvancedSearch.css';

const AdvancedSearch = () => {
    const [filters, setFilters] = useState({
        company: '',
        difficulty: '',
        type: '',
        keywords: '',
        timeframe: 'all'
    });

    const [questions, setQuestions] = useState([]);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedTags, setSelectedTags] = useState([]);

    // Sample data - Replace with actual API call
    const sampleQuestions = [
        {
            id: 1,
            title: "Design a Distributed Cache System",
            company: "Google",
            difficulty: "Hard",
            type: "System Design",
            description: "Design a distributed caching system with high availability and eventual consistency...",
            tags: ["system-design", "distributed-systems", "caching"],
            likes: 234,
            bookmarks: 56,
            timePosted: "2 days ago"
        },
        {
            id: 2,
            title: "Implement LRU Cache",
            company: "Microsoft",
            difficulty: "Medium",
            type: "Coding",
            description: "Implement a data structure for Least Recently Used (LRU) cache...",
            tags: ["data-structures", "algorithms", "cache"],
            likes: 189,
            bookmarks: 45,
            timePosted: "1 week ago"
        },
        {
            id: 3,
            title: "Database Indexing Best Practices",
            company: "Amazon",
            difficulty: "Medium",
            type: "Database",
            description: "Explain different types of database indexes and their use cases...",
            tags: ["database", "optimization", "indexing"],
            likes: 156,
            bookmarks: 34,
            timePosted: "3 days ago"
        }
    ];

    const difficulties = ['Easy', 'Medium', 'Hard'];
    const questionTypes = ['Coding', 'Theory', 'Database', 'System Design'];
    const timeframes = [
        { value: 'all', label: 'All Time' },
        { value: 'day', label: 'Last 24 Hours' },
        { value: 'week', label: 'Last Week' },
        { value: 'month', label: 'Last Month' }
    ];

    const popularTags = [
        'algorithms', 'data-structures', 'system-design', 'database',
        'frontend', 'backend', 'distributed-systems', 'machine-learning'
    ];

    useEffect(() => {
        // Simulating initial data load
        setQuestions(sampleQuestions);
    }, []);

    const handleSearch = (e) => {
        e.preventDefault();
        setIsLoading(true);

        // Simulate API call with filters
        setTimeout(() => {
            const filteredQuestions = sampleQuestions.filter(question => {
                const matchesCompany = !filters.company || 
                    question.company.toLowerCase().includes(filters.company.toLowerCase());
                const matchesDifficulty = !filters.difficulty || 
                    question.difficulty === filters.difficulty;
                const matchesType = !filters.type || 
                    question.type === filters.type;
                const matchesKeywords = !filters.keywords ||
                    question.title.toLowerCase().includes(filters.keywords.toLowerCase()) ||
                    question.description.toLowerCase().includes(filters.keywords.toLowerCase());
                const matchesTags = selectedTags.length === 0 ||
                    selectedTags.every(tag => question.tags.includes(tag));

                return matchesCompany && matchesDifficulty && 
                       matchesType && matchesKeywords && matchesTags;
            });

            setQuestions(filteredQuestions);
            setIsLoading(false);
        }, 1000);
    };

    return (
        <Container className="py-4">
            <Row>
                <Col md={3}>
                    <Card className="filter-sidebar mb-4">
                        <Card.Header className="bg-primary text-white">
                            <FontAwesomeIcon icon={faFilter} className="me-2" />
                            Filters
                        </Card.Header>
                        <Card.Body>
                            <Form onSubmit={handleSearch}>
                                <Form.Group className="mb-3">
                                    <Form.Label>
                                        <FontAwesomeIcon icon={faBuilding} className="me-2" />
                                        Company
                                    </Form.Label>
                                    <Form.Control
                                        type="text"
                                        placeholder="Enter company name"
                                        value={filters.company}
                                        onChange={(e) => setFilters({...filters, company: e.target.value})}
                                    />
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>Difficulty</Form.Label>
                                    <Form.Select
                                        value={filters.difficulty}
                                        onChange={(e) => setFilters({...filters, difficulty: e.target.value})}
                                    >
                                        <option value="">All Difficulties</option>
                                        {difficulties.map(diff => (
                                            <option key={diff} value={diff}>
                                                {diff}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>
                                        <FontAwesomeIcon icon={faCode} className="me-2" />
                                        Question Type
                                    </Form.Label>
                                    <Form.Select
                                        value={filters.type}
                                        onChange={(e) => setFilters({...filters, type: e.target.value})}
                                    >
                                        <option value="">All Types</option>
                                        {questionTypes.map(type => (
                                            <option key={type} value={type}>
                                                {type}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>
                                        <FontAwesomeIcon icon={faClock} className="me-2" />
                                        Time Frame
                                    </Form.Label>
                                    <Form.Select
                                        value={filters.timeframe}
                                        onChange={(e) => setFilters({...filters, timeframe: e.target.value})}
                                    >
                                        {timeframes.map(({ value, label }) => (
                                            <option key={value} value={value}>
                                                {label}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>
                                        <FontAwesomeIcon icon={faTags} className="me-2" />
                                        Popular Tags
                                    </Form.Label>
                                    <div className="popular-tags">
                                        {popularTags.map(tag => (
                                            <Badge
                                                key={tag}
                                                bg={selectedTags.includes(tag) ? "primary" : "secondary"}
                                                className="tag-badge me-1 mb-1"
                                                onClick={() => {
                                                    if (selectedTags.includes(tag)) {
                                                        setSelectedTags(selectedTags.filter(t => t !== tag));
                                                    } else {
                                                        setSelectedTags([...selectedTags, tag]);
                                                    }
                                                }}
                                                style={{ cursor: 'pointer' }}
                                            >
                                                #{tag}
                                            </Badge>
                                        ))}
                                    </div>
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>Keywords</Form.Label>
                                    <Form.Control
                                        type="text"
                                        placeholder="Search by keywords..."
                                        value={filters.keywords}
                                        onChange={(e) => setFilters({...filters, keywords: e.target.value})}
                                    />
                                </Form.Group>

                                <Button 
                                    variant="primary" 
                                    type="submit" 
                                    className="w-100 search-btn"
                                    disabled={isLoading}
                                >
                                    {isLoading ? (
                                        <Spinner animation="border" size="sm" className="me-2" />
                                    ) : (
                                        <FontAwesomeIcon icon={faSearch} className="me-2" />
                                    )}
                                    Search Questions
                                </Button>
                            </Form>
                        </Card.Body>
                    </Card>
                </Col>

                <Col md={9}>
                    <Card className="mb-4">
                        <Card.Body>
                            <div className="d-flex justify-content-between align-items-center mb-4">
                                <h4 className="mb-0">Search Results</h4>
                                <span className="text-muted">
                                    Found {questions.length} questions
                                </span>
                            </div>

                            {isLoading ? (
                                <div className="text-center py-5">
                                    <Spinner animation="border" variant="primary" />
                                    <p className="mt-2 text-muted">Searching questions...</p>
                                </div>
                            ) : questions.length === 0 ? (
                                <div className="text-center py-5">
                                    <p className="text-muted">No questions found matching your criteria.</p>
                                </div>
                            ) : (
                                questions.map(question => (
                                    <Card key={question.id} className="question-card mb-3">
                                        <Card.Body>
                                            <div className="d-flex justify-content-between align-items-start">
                                                <div>
                                                    <h5 className="question-title">{question.title}</h5>
                                                    <div className="mb-2">
                                                        <Badge bg="primary" className="me-2">
                                                            {question.company}
                                                        </Badge>
                                                        <Badge 
                                                            bg={
                                                                question.difficulty === 'Hard' ? 'danger' :
                                                                question.difficulty === 'Medium' ? 'warning' : 'success'
                                                            }
                                                            className="me-2"
                                                        >
                                                            {question.difficulty}
                                                        </Badge>
                                                        <Badge bg="info">{question.type}</Badge>
                                                    </div>
                                                </div>
                                                <div className="text-muted small">
                                                    <FontAwesomeIcon icon={faClock} className="me-1" />
                                                    {question.timePosted}
                                                </div>
                                            </div>
                                            
                                            <p className="question-description mb-3">
                                                {question.description}
                                            </p>

                                            <div className="d-flex justify-content-between align-items-center">
                                                <div>
                                                    {question.tags.map(tag => (
                                                        <Badge 
                                                            key={tag} 
                                                            bg="light" 
                                                            text="dark"
                                                            className="me-1"
                                                        >
                                                            #{tag}
                                                        </Badge>
                                                    ))}
                                                </div>
                                                <div>
                                                    <Button variant="outline-primary" size="sm" className="me-2">
                                                        <FontAwesomeIcon icon={faStar} className="me-1" />
                                                        {question.likes}
                                                    </Button>
                                                    <Button variant="outline-secondary" size="sm">
                                                        <FontAwesomeIcon icon={faBookmark} className="me-1" />
                                                        {question.bookmarks}
                                                    </Button>
                                                </div>
                                            </div>
                                        </Card.Body>
                                    </Card>
                                ))
                            )}
                        </Card.Body>
                    </Card>
                </Col>
            </Row>
        </Container>
    );
};

export default AdvancedSearch;
